// API Base URL
const API_BASE_URL = 'http://localhost:3000';

async function getLocalData(key) {
    try {
        const response = await fetch(`${API_BASE_URL}/${key}`);
        if (!response.ok) {
            if (response.status === 404) {
                // If endpoint doesn't exist, return empty array
                return [];
            }
            throw new Error(`Failed to fetch ${key}`);
        }
        return await response.json();
    } catch (error) {
        console.error(`Error fetching ${key}:`, error);
        return [];
    }
}

async function setLocalData(key, data) {
    try {
        // For updating existing data, we need to handle differently
        // This function assumes we're replacing all data for a key
        // First, get existing data to know what to update
        const existingData = await getLocalData(key);
        
        // Delete all existing items
        for (const item of existingData) {
            try {
                await fetch(`${API_BASE_URL}/${key}/${item.id}`, {
                    method: 'DELETE'
                });
            } catch (e) {
                // Ignore errors when deleting
            }
        }
        
        // Post all new items
        for (const item of data) {
            try {
                await fetch(`${API_BASE_URL}/${key}`, {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json'
                    },
                    body: JSON.stringify(item)
                });
            } catch (e) {
                console.error(`Error posting ${key} item:`, e);
            }
        }
    } catch (error) {
        console.error(`Error setting ${key}:`, error);
    }
}

async function initializeLocalStorage() {
    try {
        // Check if cars endpoint exists and has data
        const carsResponse = await fetch(`${API_BASE_URL}/cars`);
        if (carsResponse.status === 404) {
            // Initialize with empty array by creating the endpoint
            await fetch(`${API_BASE_URL}/cars`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ id: 'init', _dummy: true })
            });
        }
        
        // Check if clients endpoint exists
        const clientsResponse = await fetch(`${API_BASE_URL}/clients`);
        if (clientsResponse.status === 404) {
            await fetch(`${API_BASE_URL}/clients`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ id: 'init', _dummy: true })
            });
        }
        
        // Check if requests endpoint exists
        const requestsResponse = await fetch(`${API_BASE_URL}/requests`);
        if (requestsResponse.status === 404) {
            await fetch(`${API_BASE_URL}/requests`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ id: 'init', _dummy: true })
            });
        }
    } catch (error) {
        console.error('Error initializing storage:', error);
    }
}

// Initialize on load
initializeLocalStorage();

// Export functions for use in other modules
window.getLocalData = getLocalData;
window.setLocalData = setLocalData;